  ('real-estate-moex-02068', 'real-estate', 'real-estate-moex-100-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何者非屬「結合」之定義？', '["直接或間接控制他事業之業務經營或人事任免者", "受讓或承租他事業全部或主要部分之營業或財產者", "與他事業經常共同經營或受他事業委託經營者", "持有或取得他事業之股份或出資額，達到他事業有表決權股份或資本總額四分之一以上者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "83e659d50439", "answer_pdf_sha1": "3e547e95aab3", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1003", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
